note top of AspectJAutoProxyCreator
@Override
public Object postProcessAfterInitialization(Object bean, String beanName) throws Exception {
    if (bean instanceof AspectJExpressionPointcutAdvisor) {
        return bean;
    }
    if (bean instanceof MethodInterceptor) {
        return bean;
    }
    List<AspectJExpressionPointcutAdvisor> advisors = beanFactory
            .getBeansForType(AspectJExpressionPointcutAdvisor.class);
    for (AspectJExpressionPointcutAdvisor advisor : advisors) {
        if (advisor.getPointcut().matches(bean.getClass())) {
            AdvisedSupport advisedSupport = new AdvisedSupport();
            advisedSupport.setMethodInterceptor((MethodInterceptor) advisor.getAdvice());
            advisedSupport.setMethodMatcher(advisor.getPointcut());
            TargetSource targetSource = new TargetSource(bean, bean.getClass().getInterfaces());
            advisedSupport.setTargetSource(targetSource);
            return new JdkDynamicAopProxy(advisedSupport).getProxy();
        }
    }
    return bean;
}
end note

note left of JdkDynamicAopProxy
@Override
public Object getProxy() {
    return Proxy.newProxyInstance(getClass().getClassLoader(), new Class[] { advised.getTargetSource()
            .getTargetClass() }, this);
}

@Override
public Object invoke(Object proxy, final Method method, final Object[] args) throws Throwable {
    MethodInterceptor methodInterceptor = advised.getMethodInterceptor();
    if (advised.getMethodMatcher().matches(method, advised.getTargetSource().getTarget().getClass())) {
        return methodInterceptor.invoke(new ReflectiveMethodInvocation(advised.getTargetSource().getTarget(), method, args));
    }
    return method.invoke(advised.getTargetSource().getTarget(), args);
}
end note

